CREATE TABLE public.product_catalog (\n  barcode TEXT NOT NULL UNIQUE,\n  name TEXT NOT NULL,\n  photo_url TEXT NULL,\n  created_at TIMESTAMPTZ DEFAULT now() NOT NULL,\n  updated_at TIMESTAMPTZ DEFAULT now() NOT NULL\n);\n\nALTER TABLE public.product_catalog ENABLE ROW LEVEL SECURITY;\n\nCREATE POLICY "Public product_catalog is viewable by everyone." ON public.product_catalog FOR SELECT USING (TRUE);\n\nCREATE POLICY "Users can insert their own product_catalog." ON public.product_catalog FOR INSERT WITH CHECK (auth.uid() = NULL); -- Temporarily set to NULL to prevent direct user inserts, will be managed by application logic\n\nCREATE POLICY "Users can update their own product_catalog." ON public.product_catalog FOR UPDATE USING (auth.uid() = NULL); -- Temporarily set to NULL, will be managed by application logic\n\nCREATE POLICY "Users can delete their own product_catalog." ON public.product_catalog FOR DELETE USING (auth.uid() = NULL); -- Temporarily set to NULL, will be managed by application logic
